import java.lang.Math.*;
public class Line {
private static final double TOLERANCE = 1E-12;

    public static void main(String[] args) {
        Line line = new Line(); 
	line.setDirection(new Vector3D(-7456896,-4321150,98469984)); //input data here

	Vector3D v= line.getDirection().multiplyByScalar(1/(double)Math.sqrt(Math.pow(line.getDirection().getX(),2)+Math.pow(line.getDirection().getY(),2)+Math.pow(line.getDirection().getZ(),2)));  
        System.out.println(v); //output result here
	}
    private Vector3D zero = new Vector3D(0, 0, 0);
    private Vector3D direction;

    /**
     * Constructs a degenerate line at the origin with all axes as directions.
     */
    public Line() {
        this(new Vector3D(1, 1, 1), zero);
    }

    /**
     * Constructs a line with a specified direction vector, the initial point of which is defined implicitly as the origin.
     * 
     * @param dir the direction of the line.
     */
    public Line(Vector3D dir) {
        this(dir, zero);
    }

    /**
     * Constructs a line given its direction and initial point.
     * 
     * @param dir the direction of the line.
     * @param pointOnLine any point on the line.
     */
    public Line(Vector3D dir, Vector3D pointOnLine) {
        if (Math.abs(dir.dotProduct(pointOnLine)) > TOLERANCE) {
            throw new IllegalArgumentException("The provided point must lie on the line");
        }
        direction = dir;
    }
    public Vector3D getDirection(){
        return direction;
    }
    public void setDirection(Vector3D direction){
        this.direction=direction;
    }

}

